import { getSession } from "@/lib/auth";
import { StatCard } from "@/components/ui/Card";
import { Badge } from "@/components/ui/Badge";
import { RatingBadge } from "@/components/ui/RatingBadge";
import { Calendar, CheckCircle, Clock, TrendingUp } from "lucide-react";

// Placeholder dashboard — will be replaced with live data in Phase 2.
export default async function DashboardPage() {
  const session = await getSession();
  if (!session) return null;

  const { role, name } = session;

  return (
    <div className="space-y-6">
      {/* Greeting */}
      <div>
        <h1 className="text-lg font-bold text-text-primary">
          Good morning, {name.split(" ")[0]}
        </h1>
        <p className="text-xs text-text-secondary mt-0.5">
          Here&apos;s what needs your attention today.
        </p>
      </div>

      {/* Stats row */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="Current Month Score" value="—" sub="Pending review" />
        <StatCard
          label="Cycle Status"
          value="Pending"
          sub="Self-score due by 5th"
          color="orange"
        />
        <StatCard label="Weeks This Month" value="3" sub="Reflections submitted" color="blue" />
        <StatCard label="Annual Average" value="—" sub="7 months remaining" />
      </div>

      {/* Pending actions */}
      <div className="enterprise-card p-5">
        <h2 className="font-semibold text-sm text-primary-900 mb-4">Pending Actions</h2>
        <div className="space-y-3">
          {role === "employee" || role === "manager" ? (
            <>
              <PendingItem
                icon={<Calendar size={15} />}
                title="Submit Monthly Self-Score"
                subtitle="Due by the 5th of this month"
                urgency="high"
              />
              <PendingItem
                icon={<CheckCircle size={15} />}
                title="Weekly Reflection"
                subtitle="Last submitted: 3 days ago"
                urgency="low"
              />
            </>
          ) : null}
          {role === "manager" && (
            <PendingItem
              icon={<TrendingUp size={15} />}
              title="Score Your Team"
              subtitle="3 team members awaiting your review"
              urgency="medium"
            />
          )}
          {(role === "hr" || role === "md") && (
            <PendingItem
              icon={<Clock size={15} />}
              title="Pending Escalations"
              subtitle="2 reviews overdue — action required"
              urgency="high"
            />
          )}
        </div>
      </div>

      {/* This month's cycle */}
      <div className="enterprise-card p-5">
        <h2 className="font-semibold text-sm text-primary-900 mb-4">
          This Month&apos;s Review Cycle
        </h2>
        <div className="flex items-center gap-4">
          <Badge variant="pending" label="Pending Self-Score" size="md" />
          <span className="text-sm text-gray-500">
            Window open: 1st – 11th March 2026
          </span>
        </div>
        <div className="mt-4 grid grid-cols-3 gap-3">
          <div className="rounded-lg bg-gray-50 p-3 text-center">
            <p className="text-xs text-gray-500 mb-1">Self Score</p>
            <RatingBadge score={0} size="md" />
          </div>
          <div className="rounded-lg bg-gray-50 p-3 text-center">
            <p className="text-xs text-gray-500 mb-1">Manager Score</p>
            <RatingBadge score={0} size="md" />
          </div>
          <div className="rounded-lg bg-gray-50 p-3 text-center">
            <p className="text-xs text-gray-500 mb-1">Average</p>
            <RatingBadge score={0} size="md" />
          </div>
        </div>
      </div>

      <p className="text-xs text-gray-400 text-center">
        Live data will populate once your manager sets up your goals/tasks and the review window opens.
      </p>
    </div>
  );
}

function PendingItem({
  icon,
  title,
  subtitle,
  urgency,
}: {
  icon: React.ReactNode;
  title: string;
  subtitle: string;
  urgency: "high" | "medium" | "low";
}) {
  const dot =
    urgency === "high"
      ? "bg-red-500"
      : urgency === "medium"
      ? "bg-amber-500"
      : "bg-gray-300";

  return (
    <div className="flex items-center gap-3 py-2.5 border-b border-gray-50 last:border-0">
      <div className="w-8 h-8 rounded-lg bg-primary-50 flex items-center justify-center text-primary-600 flex-shrink-0">
        {icon}
      </div>
      <div className="flex-1 min-w-0">
        <p className="text-sm font-medium text-primary-900 truncate">{title}</p>
        <p className="text-xs text-gray-500">{subtitle}</p>
      </div>
      <span className={`w-2 h-2 rounded-full flex-shrink-0 ${dot}`} />
    </div>
  );
}
